import { cx } from '@/utils/cx';
import { HintText } from '@/components/atoms/Input/base/hint-text';
import { ComponentPropsWithRef } from 'react';

export type HintProps = ComponentPropsWithRef<typeof HintText> & {
  isWarning?: boolean;
};

export function Hint({ isWarning, children, ...props }: HintProps) {
  return (
    <HintText
      {...props}
      className={cx(isWarning && 'text-warning-primary')}
    >
      {children}
    </HintText>
  );
}
