import { useCallback, useEffect, useRef, useState } from 'react';

/**
 * Detects whether the referenced element's content overflows its container.
 *
 * - `axis: 'x'` — single-line / horizontal truncation (`scrollWidth > clientWidth`).
 *   Pair with `whitespace-nowrap overflow-hidden text-ellipsis`.
 * - `axis: 'y'` — multi-line / vertical truncation (`scrollHeight > clientHeight`).
 *   Pair with `line-clamp-N` or a fixed-height container with `overflow-hidden`.
 *
 * Re-checks on element resize via `ResizeObserver`.
 */
export function useTruncation<T extends HTMLElement>(axis: 'x' | 'y') {
  const ref = useRef<T>(null);
  const [isTruncated, setIsTruncated] = useState(false);

  const check = useCallback(() => {
    const el = ref.current;
    if (!el) return;
    setIsTruncated(
      axis === 'y'
        ? el.scrollHeight > el.clientHeight
        : el.scrollWidth > el.clientWidth,
    );
  }, [axis]);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    check();
    const ro = new ResizeObserver(check);
    ro.observe(el);
    return () => ro.disconnect();
  }, [check]);

  return { ref, isTruncated };
}
